body:
How may we help - what is your question?

Please see the code example below.  This is a trivial example to illustrate.  Some IPs have clocks and resets (functional pervasive) embedded in structs and some IPs have explicit clocks and resets for ports.  When a leaf node that has explicit clocks and reset ports (module_B) is instantiated inside a module that has a pervasive struct (module_A) the clock appears to not propagate.   Is this expected Verilator behaviour?

```
XXX@MacBook-Pro-6 tb % verilator --version
Verilator 5.013 devel rev v5.012-54-gced1dfeff
```

I have also tried various combinations of --clk and /\*verilator clocker\*/, etc.

```
--clk tb.module_A.module_B.clk1x

module module_B(
   input logic  clk1x /*verilator clocker*/
   ,input logic reset
```

<img width="816" alt="image" src="https://github.com/verilator/verilator/assets/92717390/8bbee523-263c-4875-bb0c-1a09288799cf">

```

typedef struct packed {
   logic clk1x;
   logic reset;
} cnr_t;

module module_B(
   input logic clk1x
   ,input logic reset
   ,input logic A
   ,output logic B
);

   always_ff @(posedge clk1x) begin
      if(reset) begin
         B <= 'b0;
      end else begin
         B <= A;
      end
   end

endmodule

module module_A(
   input cnr_t cnr
   ,input logic A
   ,output logic B
);

   module_B module_B(
      .clk1x(cnr.clk1x)
      ,.reset(cnr.reset)
      ,.A(A)
      ,.B(B)
   );

endmodule

module tb();

   cnr_t cnr;
   logic A, B;

   module_A module_A(
      .cnr(cnr)
      ,.A(A)
      ,.B(B)
   );

   always #10 cnr.clk1x = ~cnr.clk1x;

   initial begin
      $dumpfile("tb.vcd");
      $dumpvars(0, tb);

      cnr.reset = 'b1;
      A = 'b0;

      #20;
      cnr.reset = 'b0;

      #20;
      A = 'b1;

      #20;
      A = 'b0;

      #100;
      $finish;
   end

endmodule
```
